const items = [
  { id: 'TD-001', title: 'Legacy auth middleware still uses synchronous bcrypt', area: 'backend/auth', description: 'The auth middleware uses bcrypt.compareSync() which blocks the event loop. Under concurrent login spikes this creates latency for all active requests, not just authentication ones.', age_months: 14, reported_by: 'Senior BE engineer', workaround: 'Rate limit login endpoint', risk: 'Under a DDoS-style login flood this could take down all API endpoints simultaneously' },
  { id: 'TD-002', title: 'Frontend task list re-renders entire list on any state change', area: 'frontend/performance', description: 'The task list component has no memoisation. Any change to any task (even in another project) triggers a full re-render of the entire task list. With 200+ tasks this causes noticeable jank.', age_months: 8, reported_by: 'Frontend engineer', workaround: 'None — visible to users with large projects', risk: 'Users with large projects experience degraded UI performance' },
  { id: 'TD-003', title: 'Direct database access in three API routes bypasses ORM', area: 'backend/data', description: 'Routes /api/v1/admin/stats, /api/v1/reports/export, and /api/v1/billing/usage use raw SQL queries that bypass the ORM layer. These routes are not covered by the connection pool and lack the query timeout middleware.', age_months: 22, reported_by: 'Staff engineer', workaround: 'None', risk: 'A slow query on these routes can exhaust the database connection pool, affecting all other queries' },
  { id: 'TD-004', title: 'CSS bundle includes unused component styles', area: 'frontend/build', description: 'The CSS bundle (340kb gzipped) includes styles for 12 deprecated components that were removed from the UI 6 months ago. PurgeCSS is not configured.', age_months: 6, reported_by: 'Frontend engineer', workaround: 'None needed — cosmetic issue only', risk: 'Bundle size slightly increases initial page load time' }
];
return [{ json: { items, product: 'ProjectFlow', sprint_capacity_available: 8 } }];

const { items, product, sprint_capacity_available } = $input.first().json;
const itemsText = items.map(i => `  [${i.id}] ${i.title} (${i.area}, ${i.age_months}mo old)
  ${i.description}
  Risk: ${i.risk}
  Workaround: ${i.workaround}`).join('

');
const system = `You are a staff engineer reviewing a tech debt register to help a PM and engineering manager prioritise paydown. You score each item using three dimensions: (1) blast radius — how many users/systems are affected if this fails; (2) velocity tax — how much this slows down feature development; (3) risk trajectory — is this getting worse over time? Return ONLY valid JSON.`;
const user = `Score and prioritise this tech debt register for: ${product}
Sprint capacity available for debt paydown: ${sprint_capacity_available} story points

Debt items:
${itemsText}

Return JSON:
{
  "scored_items": [
    {
      "id": "string",
      "blast_radius": "high|medium|low",
      "velocity_tax": "high|medium|low",
      "risk_trajectory": "increasing|stable|decreasing",
      "priority_rank": 1,
      "estimated_effort_points": 5,
      "recommended_action": "pay-now|schedule-next-quarter|monitor|accept",
      "rationale": "string"
    }
  ],
  "paydown_recommendation": "string — which items to tackle this sprint given the capacity",
  "total_estimated_effort": 0
}`;
return [{ json: { items, sprint_capacity_available, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Scoring Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.scored_items || !Array.isArray(parsed.scored_items)) return [{ json: { _error: true, reason: 'Missing scored_items' } }];
return [{ json: { _error: false, result: parsed, source_items: upstream.items, meta: { item_count: upstream.items.length, sprint_capacity: upstream.sprint_capacity_available, generated_at: new Date().toISOString() } } }];

const { result: r, source_items: src, meta: m } = $input.first().json;
const sorted = [...(r.scored_items||[])].sort((a,b) => a.priority_rank - b.priority_rank);
const lines = sorted.map(s => {
  const orig = src.find(i => i.id === s.id) || {};
  return [
    `  [#${s.priority_rank}] ${s.id}: ${orig.title || ''}`,
    `  Blast radius: ${s.blast_radius} | Velocity tax: ${s.velocity_tax} | Risk trend: ${s.risk_trajectory}`,
    `  Action: ${s.recommended_action.toUpperCase()} | Effort: ${s.estimated_effort_points}pt`,
    `  Rationale: ${s.rationale}`,
    ''
  ].join('\n');
}).join('\n');
const report = [
  `TECH DEBT REGISTER: ${m.item_count} items | Sprint capacity: ${m.sprint_capacity}pt | Generated: ${m.generated_at}`,
  ``,
  `SPRINT RECOMMENDATION: ${r.paydown_recommendation}`,
  `Total estimated effort: ${r.total_estimated_effort}pt`,
  ``,
  `DEBT ITEMS (priority order):`,
  lines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
